// package-lock-generator.js

const fs = require('fs');
const { execSync } = require('child_process');

function generatePackageLock() {
  try {
    // Ensure the package.json file exists
    if (!fs.existsSync('./package.json')) {
      throw new Error('No package.json file found in the current directory.');
    }

    // Run npm install to generate package-lock.json
    execSync('npm install', { stdio: 'inherit' });

    console.log('package-lock.json has been generated successfully.');
  } catch (error) {
    console.error('Error generating package-lock.json:', error.message);
  }
}

// Example usage
